def generate(seed):
    rng = random.Random(seed)

    p = rng.choice([3, 5, 7, 11, 13, 17, 19, 23, 29])
    a = rng.randint(1, p - 1)
    k = rng.randint(1, 4)
    if k == 1:
        answer = a
    else:
        for i in range(1, p):
            if pow(i, k, p) == a:
                answer = i
                break
        else:
            answer = "No solution"
    problem = (
        f"Find the {k}-th root of {a} modulo {p}. "
        f"If no solution exists, state that there is no solution."
    )

